# parse_error.py -- vendor-agnostic error body extractor
import httpx
from typing import Any

def extract_error_message(response: httpx.Response) -> str:
    """Return a human-readable error string from any vendor's JSON error body."""
    try:
        body: Any = response.json()
    except Exception:
        return response.text[:200] or f"HTTP {response.status_code}"

    # Probe common vendor shapes in priority order
    for path in [
        ["error", "message"],       # Anthropic, Stripe, OpenAI
        ["error", "detail"],        # some REST APIs
        ["message"],                # GitHub, many simple APIs
        ["detail"],                 # FastAPI / Django REST Framework
        ["errors", 0, "message"],   # GraphQL-wrapped REST
    ]:
        val: Any = body
        try:
            for key in path:
                val = val[key]
            if isinstance(val, str) and val:
                return val
        except (KeyError, IndexError, TypeError):
            continue
    return f"HTTP {response.status_code}"

# retry_client.py -- API call with tenacity retry and error classification
# pip install httpx tenacity

import random
import httpx
from tenacity import (
    retry, stop_after_attempt, wait_exponential, retry_if_exception,
    before_sleep_log, RetryError,
)
import logging

log = logging.getLogger(__name__)

RETRYABLE_STATUS = {429, 500, 502, 503, 504}

def is_retryable(exc: BaseException) -> bool:
    if isinstance(exc, httpx.HTTPStatusError):
        return exc.response.status_code in RETRYABLE_STATUS
    if isinstance(exc, (httpx.ConnectTimeout, httpx.ReadTimeout, httpx.ConnectError)):
        return True
    return False

def get_retry_after(exc: BaseException) -> float:
    if isinstance(exc, httpx.HTTPStatusError):
        val = exc.response.headers.get("Retry-After")
        if val:
            try:
                return float(val)
            except ValueError:
                pass
    return 0.0

@retry(
    stop=stop_after_attempt(5),
    wait=wait_exponential(multiplier=1, min=1, max=30),
    retry=retry_if_exception(is_retryable),
    before_sleep=before_sleep_log(log, logging.WARNING),
    reraise=True,
)
async def fetch_with_retry(client: httpx.AsyncClient, url: str) -> dict:
    r = await client.get(url)
    if r.status_code in RETRYABLE_STATUS:
        r.raise_for_status()
    if r.status_code >= 400:
        body = r.json() if r.headers.get("content-type", "").startswith("application/json") else {}
        raise httpx.HTTPStatusError(
            f"HTTP {r.status_code}: {body.get('message', r.text[:200])}",
            request=r.request,
            response=r,
        )
    return r.json()

# circuit_breaker.py -- wrap a flaky API with a circuit breaker
# pip install httpx pybreaker

import httpx
import pybreaker

# Open circuit after 5 consecutive failures; try again after 30s
breaker = pybreaker.CircuitBreaker(fail_max=5, reset_timeout=30)

@breaker
async def call_flaky_api(client: httpx.AsyncClient, path: str) -> dict:
    r = await client.get(path)
    r.raise_for_status()
    return r.json()

async def safe_call(client: httpx.AsyncClient, path: str) -> dict | None:
    try:
        return await call_flaky_api(client, path)
    except pybreaker.CircuitBreakerError:
        # Circuit is open -- upstream is down; do not retry
        return None
    except httpx.HTTPStatusError as exc:
        if exc.response.status_code in {400, 401, 403, 404, 422}:
            raise  # non-retryable; propagate immediately
        raise  # retryable; let tenacity handle it upstream
